var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사진부 문제는 어떻게든 해결했으니, 다음은 후야제 캠프파이어 준비인데…….","JPN":"写真部の件はなんとかなったから、後は後夜祭のキャンプファイヤーの準備だけど……","ENG":"The photography club's complaint seems to have been resolved. Next is to help with the post-festival party preparations...","TWN":"攝影部的問題總算是解決了，接下來是準備慶功宴的營火……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"콜록, 콜록! 먼지가 엄청 쌓였잖아?","JPN":"ゴホッ、ゴホッ！　すごい埃。","ENG":"*Cough!* *Cough!* Look at all this dust!","TWN":"咳咳，咳咳！怎麼這麼多灰塵？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어디보자, 분명 캠프파이어에 쓸 장작이 여기에 있다고 했지.","JPN":"ええと、確かここにキャンプファイヤーに使う薪があるって聞いたけど……","ENG":"Let's see here. I was told there'd be some firewood for the campfire here.","TWN":"我看看，營火要用的木柴說是放在這裡吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음? 뭐지? 이 상자만 유난히 먼지 하나 없이 말끔한데.","JPN":"あれ、なんだろう？　この箱だけ埃がかぶってなくてキレイだ。","ENG":"Mm? That's odd. This is the only box that's not caked with dust.","TWN":"嗯？這是怎樣？只有這個箱子超乾淨，一點灰塵都沒有。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"자, 잠깐……! 이거 사진부에서 잃어버렸다고 했던 사진이잖아?","JPN":"これは！？　これって写真部が無くしたって言ってた写真じゃない？","ENG":"W-wait...! Aren't these the missing photos?!","TWN":"這，等等……！這不是攝影部不見的照片嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이게 왜 학생회실 창고에 있는 거지?","JPN":"どうして、そんなものが生徒会室の倉庫に……","ENG":"But why would they be in the Student Council storage room?","TWN":"為什麼會在學生會辦公室裡？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"기름 통에서 기름이 조금씩……","JPN":"油缶から油が少しずつ……","ENG":"It's been trickling...","TWN":"汽油桶裡的油有點……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"이렇게 눈에 띄지 않는 곳에 있으니까…….","JPN":"こんな目立たない場所にあったせいで……","ENG":"No wonder they couldn't find the cause...","TWN":"放在這種不起眼的地方……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"누가 이런 곳에 기름통을…….","JPN":"誰がこんな場所に油缶を……","ENG":"Who would hide this...","TWN":"誰會把汽油桶……"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"윽. 이 기억은……?","JPN":"うっ。この記憶は……？","ENG":"Ngh. What are these memories...?","TWN":"唔，這是……？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마, 그동안 누군가 학원제를 방해하려고 했던 건가? 대체 누가?","JPN":"まさか、今まで誰かが学園祭を邪魔しようとしていた？　いったい誰が？","ENG":"Could someone be trying to sabotage the festival? But who?","TWN":"該不會是有人想要破壞學園祭？會是誰呢？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아, 여기 있었군. 유미나.","JPN":"ああ、ここにいたのか、ミナ。","ENG":"Oh, there you are, Yoo Mina.","TWN":"原來你這裡，劉米娜。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"르, 를르슈!?","JPN":"ル、ルルーシュ。","ENG":"L-Lelouch?!","TWN":"魯，魯路修！？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"왜 그러지? 안색이 좋지 않은데?","JPN":"どうした？　顔色が良くないみたいだが……","ENG":"What's wrong? You don't look so good.","TWN":"你怎麼了？臉色不太好。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아하하, 별 거 아니야. 그보다 무슨 일이야?","JPN":"あはは……、そんなことないよ。それより私に用事？","ENG":"Ah hah hah. N-nothing. What brings you here?","TWN":"哈哈哈，沒什麼，你找我有事嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아니, 촬영회 때문에 왠지 지쳐 보이는 것 같아서. 후야제 준비는 우리한테 맡기고 조금 쉬는 게 어때.","JPN":"いや、撮影会で疲れていたみたいだったからな。後夜祭の準備は他の人間に任せて休んだ方がと思って……","ENG":"Oh, you just looked exhausted after the photoshoot. So why don't you leave the rest to us and take five?","TWN":"我是想說，你在攝影展上有點累的樣子，\\n不如慶功宴就交給我們準備，你去休息一下吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아아, 뭐. 딱히 신경 쓰지 않아도 괜찮아, 를르슈.","JPN":"ううん、大丈夫。そんなに気にしないで、ルルーシュ。","ENG":"Oh. Well, you don't have to worry about me, Lelouch.","TWN":"喔喔～我沒事，不用顧慮我，魯路修。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그래? 그럼 다행이네. 솔직히 미나가 장작을 쌓아 본 적있다고 해서 안심했거든.","JPN":"そうか。正直、助かるよ。ミナは薪を組んだことがあるって言っていたから頼りにしてるんだ。","ENG":"Really? That takes the load off my shoulders. To be honest, I was relieved to hear that you have experience in stacking firewood.","TWN":"是嗎？那就好。你說你堆過木柴，所以我很放心呢。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 왠지 모르게 쌓을 수 있을 것 같아서.","JPN":"そうだね。前にも学校でこうしたキャンプファイヤーを……","ENG":"Yeah. I just have a feeling that I can.","TWN":"嗯，我就覺得我會堆的感覺。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어라? 그런데 내가 어떻게 장작 쌓는 법 같은 걸 알고 있는 거지?","JPN":"あれ？　でも、どうして私、そんなこと知ってるんだろう。","ENG":"Huh? But how do I know how to stack firewood?","TWN":"嗯？不過為什麼我會知道怎麼堆呢？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"미나, 너는 그런 적 없어?","JPN":"ミナ……、お前はこんな経験がないか？","ENG":"Mina, have you ever experienced it before?","TWN":"米娜，你沒堆過嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};